      dogs: { title: "Huskies und Tierwohl", intro: "Huskyfarmen in Levi sorgen hervorragend für ihre Tiere:", items: ["Hunde lieben es zu laufen und sind für diese Arbeit trainiert","Jeder Hund erhält individuelle Pflege und Aufmerksamkeit","Regelmäßige tierärztliche Kontrollen","Ausgewogene Arbeits- und Ruhezeiten","Pensionierte Hunde werden in liebevolle Heime vermittelt"], tip: "Sie dürfen die Hunde vor und nach der Fahrt streicheln – sie lieben Aufmerksamkeit!" },
      clothing: { title: "Was Sie anziehen sollten", intro: "Safari-Anbieter stellen normalerweise warme Overalls. Bringen Sie trotzdem mit:", items: ["Woll- oder Thermounterwäsche (keine Baumwolle)","Warme Wollsocken","Dünne Mütze unter Helm oder Kapuze","Gesichtsschutz oder Schlauchschal","Eigene Handschuhe als Backup (wenn wärmer)"], tip: "Sie sitzen ziemlich still im Schlitten, also ziehen Sie sich warm an! Der Musher bewegt sich mehr." },
      driving: { title: "Schlitten fahren – praktische Tipps", items: [
        { title: "Kein Führerschein nötig", text: "Für Hundeschlittenfahren brauchen Sie keinen Führerschein. Der Guide erklärt Schlittenhandhabung und Bremsung vor der Abfahrt." },
        { title: "Bremsen und Lenken", text: "Der Schlitten hat eine Bremse, auf die Sie mit dem Fuß treten. Die Hunde ziehen – Ihre Aufgabe ist bremsen und durch Gewichtsverlagerung lenken." },
        { title: "Als Passagier", text: "Sie können auch im Schlitten als Passagier sitzen. Ideal für Kinder oder alle, die einfach die Landschaft genießen möchten." },
        { title: "Umgang mit den Hunden", text: "Behandeln Sie die Hunde sanft. Streicheln ja, aber nicht ohne Erlaubnis füttern. Die Hunde sind freundlich und begeistert." },
      ]},
      bestTime: { title: "Beste Zeit für Husky-Safari", intro: "Husky-Safaris von November bis April, beste Zeiten:", times: [
        { period: "Weihnachten–Januar", desc: "Polarnacht schafft magische Atmosphäre. Möglichkeit, mit Nordlichtbeobachtung zu kombinieren." },
        { period: "Februar–März", desc: "Beste Bedingungen: viel Schnee, längeres Tageslicht, sonniges Wetter." },
        { period: "März–April", desc: "Frühlingssonne wärmt, aber noch genug Schnee. Besonders schöne Zeit." },
      ]},
      booking: { title: "Safari buchen", providers: { title: "Wo buchen", list: ["Huskyfarmen und Safari-Anbieter bei Levi","Hotel- und Unterkunftsrezeptionen","Online-Buchungen direkt bei Anbietern","Visit Levi Servicepunkt"] }, prices: { title: "Richtpreise", list: ["30 Min. Fahrt: z.B. ab ca. €80/Person","1 Std. Fahrt: z.B. ab ca. €100/Person","Halbtages-Safari: z.B. ab ca. €150/Person","Aktuelle Preise immer direkt beim Anbieter prüfen"] }, tip: "Buchen Sie frühzeitig in der Hochsaison! Husky-Safaris sind beliebt und schnell ausgebucht." },
      faq: { title: "Häufig gestellte Fragen", items: [
        { q: "Brauche ich einen Führerschein für Husky-Safari?", a: "Nein, für Hundeschlittenfahren brauchen Sie keinen Führerschein. Der Guide gibt vor der Abfahrt Anweisungen. Jeder Erwachsene kann den Schlitten fahren." },
        { q: "Können Kinder an Husky-Safaris teilnehmen?", a: "Ja! Kinder können im Schlitten sitzen oder mit einem Elternteil mitfahren. Das Mindestalter beträgt normalerweise ca. 4 Jahre. Warme Overalls und Ausrüstung werden gestellt." },
        { q: "Ist es kalt auf einer Husky-Safari?", a: "Sie sitzen recht still im Schlitten, also ziehen Sie sich warm an. Anbieter stellen Overalls und Decken. In Pausen können Sie sich am Lagerfeuer aufwärmen." },
        { q: "Sind Huskies freundlich?", a: "Ja! Schlittenhunde sind trainiert und an Menschen gewöhnt. Sie lieben Aufmerksamkeit und Streicheleinheiten. Man kann die Hunde oft vor und nach der Fahrt kennenlernen." },
        { q: "Wie viele Hunde ziehen einen Schlitten?", a: "Typischerweise 4–6 Hunde ziehen einen Schlitten. Bei längeren Safaris können es mehr sein. Die Hunde sind begeistert und lieben ihre Arbeit!" },
      ]},
